#!/usr/bin/env node
/**
 * Map the human-edited vi translations (keyed by the camelCase names in
 * src/i18n/messages.ts) onto the auto-generated hash ids in
 * src/i18n/lang/en.json.
 *
 * We pair by `defaultMessage` text. The source-of-truth English file is
 * generated by `formatjs extract`; this script translates each entry by
 * looking the English string up in src/i18n/translations/vi.json.
 *
 * Run via `npm run i18n:extract` (post-extract step).
 */
import fs from 'node:fs';
import path from 'node:path';
import url from 'node:url';

const __dirname = path.dirname(url.fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, '..');

const enHashFile = path.join(root, 'src/i18n/lang/en.json');
const viNamedFile = path.join(root, 'src/i18n/translations/vi.json');
const viHashOut = path.join(root, 'src/i18n/lang/vi.json');

const enHash = JSON.parse(fs.readFileSync(enHashFile, 'utf8'));
const viNamed = JSON.parse(fs.readFileSync(viNamedFile, 'utf8'));

// viNamed: { englishString: vietnameseString }
// enHash:  { hashId: englishString }
const result = {};
const missing = [];
for (const [hashId, englishMsg] of Object.entries(enHash)) {
  const vi = viNamed[englishMsg];
  if (vi) {
    result[hashId] = vi;
  } else {
    missing.push(englishMsg);
  }
}

fs.mkdirSync(path.dirname(viHashOut), { recursive: true });
fs.writeFileSync(viHashOut, JSON.stringify(result, null, 2) + '\n');
console.log(`✓ wrote ${Object.keys(result).length} vi translations to ${path.relative(root, viHashOut)}`);
if (missing.length) {
  console.warn(`⚠ ${missing.length} English strings have no vi translation:`);
  for (const m of missing) console.warn(`  - ${JSON.stringify(m)}`);
  process.exit(1);
}
